import React, {useState, useRef, useEffect} from 'react'
import styled from 'styled-components'
import {getDesigner} from '../WebAPI'


const DropDownWrapper = styled.div `
padding:20px 40px;
width:1000px;
height:300px;
top:30px;
bottom:0;
left:0;
right:0;
margin:0 auto;
border-radius:3px;
border:1px solid yellow;
display:flex;
align-items:center;
justidy-content:space-between;
position:absolute;
color:#1C1C1C;
background-color:white;
z-index:3;
`

const Title = styled.div `
font-size:1.3rem;
font-weight:200;
`

const Section = styled.div `
width:20%;
height:80%;
font-size:1rem;
`

export default function DesignerDropdown() {
	const [designer, setDesigner] = useState([{}])

	useEffect(() => {
		getDesigner(setDesigner)
	},[])



	return (
		<DropDownWrapper>
			<Title>Designers A-Z</Title>
			{designer.map(designer => <Section key={`${designer.id}:${designer.index}`}>{designer.name}</Section>)}
		</DropDownWrapper>
	)
}
